async (params, browser) => {
  // Search Google Scholar
  await browser.open(`https://scholar.google.com/scholar?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.gs_r.gs_or.gs_scl, #gs_res_ccl', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.gs_r.gs_or.gs_scl'); for (let i = 0; i < Math.min(items.length, 10); i++) { const el = items[i]; const titleEl = el.querySelector('.gs_rt a'); const titleFallback = el.querySelector('.gs_rt'); const snippetEl = el.querySelector('.gs_rs'); const authorEl = el.querySelector('.gs_a'); const citedByEl = el.querySelector('.gs_fl a[href*="cites"]'); const linkEl = el.querySelector('.gs_rt a'); const pdfEl = el.querySelector('.gs_or_ggsm a, a[href*="pdf"]'); const yearMatch = authorEl ? authorEl.textContent.match(/(\d{4})/) : null; results.push({ title: titleEl ? titleEl.textContent.trim() : (titleFallback ? titleFallback.textContent.trim() : ''), url: linkEl ? linkEl.href : '', pdf_url: pdfEl ? pdfEl.href : '', authors_info: authorEl ? authorEl.textContent.trim() : '', year: yearMatch ? yearMatch[1] : '', snippet: snippetEl ? snippetEl.textContent.trim().substring(0, 500) : '', cited_by: citedByEl ? citedByEl.textContent.trim() : '' }); } var params = new URLSearchParams(window.location.search); return { query: params.get('q') || '', result_count: results.length, results: results }`)

  return search_results
}
